/**
 * Returns Office roaming settings when the host supports it.
 */
function getRoamingSettings() {
  const ctx = Office?.context;
  return ctx && ctx.roamingSettings ? ctx.roamingSettings : null;
}

/**
 * ตรวจสอบว่าอ็อบเจ็กต์เพย์โหลดมีรายการสิ่งอำนวยความสะดวกอย่างน้อยหนึ่งรายการหรือไม่
 */
function hasAmenitiesPayload(payload) {
  return Boolean(payload && typeof payload === "object" && Object.keys(payload).length > 0);
}

/**
 * อ่านค่า itemId จากรายการ Outlook ปัจจุบันและปรับให้เป็นค่ามาตรฐาน
 */
function extractInlineItemId(item) {
  if (!item || typeof item.itemId !== "string") return "";
  const itemId = item.itemId.trim();
  return itemId || "";
}

/**
 * ส่งคืนค่าจริงเมื่อรายการปัจจุบันมี itemId ที่บันทึกไว้แล้ว
 */
function hasSavedItemId(item) {
  return Boolean(extractInlineItemId(item));
}

/**
 * Gets a reliable saved itemId using inline value or getItemIdAsync fallback.
 */
function getSavedItemIdAsync(item) {
  const inlineId = extractInlineItemId(item);
  if (inlineId) return Promise.resolve(inlineId);
  if (!item || typeof item.getItemIdAsync !== "function") return Promise.resolve("");

  return new Promise((resolve) => {
    try {
      item.getItemIdAsync((res) => {
        if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve("");
        if (typeof res.value !== "string") return resolve("");
        const id = res.value.trim();
        return resolve(id || "");
      });
    } catch (error) {
      return resolve("");
    }
  });
}

/**
 * Asynchronously checks whether the current item has a saved id.
 */
async function hasSavedItemIdAsync(item) {
  const id = await getSavedItemIdAsync(item);
  return Boolean(id);
}

/**
 * Parses JSON payload text and safely returns an amenities object.
 */
function parseAmenitiesPayload(raw, sourceLabel) {
  if (!raw || typeof raw !== "string") return {};

  try {
    const parsed = JSON.parse(raw);
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch (error) {
    console.warn(`${sourceLabel} is not valid JSON:`, error);
    return {};
  }
}

/**
 * Normalizes text for matching by trimming and lowercasing.
 */
function normalizeText(value) {
  return String(value || "").trim().toLowerCase();
}

/**
 * Normalizes mailbox-like values (SMTP/mailto/email) into lowercase email.
 */
function normalizeMailboxAddress(value) {
  const raw = String(value || "").trim();
  if (!raw) return "";

  const protocolMatch = raw.match(/^(?:smtp:|mailto:)(.+)$/i);
  const withoutProtocol = protocolMatch && protocolMatch[1] ? protocolMatch[1].trim() : raw;
  const angleMatch = withoutProtocol.match(/<([^>]+)>/);
  const candidate = angleMatch && angleMatch[1] ? angleMatch[1].trim() : withoutProtocol;
  return candidate.includes("@") ? candidate.toLowerCase() : "";
}

/**
 * Parses a value and returns UTC ISO text when possible.
 */
function toUtcIsoString(value) {
  if (!value) return "";
  if (value instanceof Date) {
    return Number.isNaN(value.getTime()) ? "" : value.toISOString();
  }

  const text = String(value).trim();
  if (!text) return "";

  const hasOffset = /(?:z|[+-]\d{2}:\d{2})$/i.test(text);
  const parsed = new Date(hasOffset ? text : `${text}Z`);
  return Number.isNaN(parsed.getTime()) ? "" : parsed.toISOString();
}

/**
 * Parses Graph dateTimeTimeZone shape into UTC ISO text.
 */
function parseGraphDateTimeZoneToUtc(value) {
  if (!value || typeof value !== "object") return "";
  return toUtcIsoString(value.dateTime || "");
}

/**
 * Escapes an OData string literal.
 */
function escapeODataString(value) {
  return String(value || "").replace(/'/g, "''");
}

/**
 * Creates a plain JSON-safe copy of amenities payload.
 */
function cloneAmenitiesPayload(payload) {
  if (!payload || typeof payload !== "object") return {};
  try {
    return JSON.parse(JSON.stringify(payload));
  } catch (error) {
    return {};
  }
}

/**
 * Resolves the payload snapshot to persist/sync.
 */
function resolveAmenitiesForPersistence(explicitPayload) {
  if (explicitPayload && typeof explicitPayload === "object") return explicitPayload;
  if (pendingPayload && typeof pendingPayload === "object") return pendingPayload;
  const uiPayload = collectAmenitiesPayload();
  return uiPayload && typeof uiPayload === "object" ? uiPayload : {};
}

/**
 * Extracts selected amenity codes as unique values.
 */
function getSelectedAmenityCodes(payload) {
  const codes = new Set();
  Object.entries(payload || {}).forEach(([label, entry]) => {
    if (!entry || typeof entry !== "object") return;
    const qty = Number(entry.qty) || 0;
    const isSelected = Boolean(entry.selected) || qty > 0;
    if (!isSelected) return;
    const code = String(entry.code || label || "").trim();
    if (code) codes.add(code);
  });
  return Array.from(codes);
}

/**
 * Extracts room mailbox addresses from Graph event locations.
 */
function extractRoomMailboxesFromGraphEvent(graphEvent) {
  const locations = Array.isArray(graphEvent?.locations) ? graphEvent.locations : [];
  const mailboxes = new Set();

  locations.forEach((loc) => {
    const locationType = normalizeText(loc?.locationType);
    const looksLikeRoom = !locationType || locationType.includes("room") || locationType.includes("conference");
    if (!looksLikeRoom) return;

    const candidates = [
      loc?.locationEmailAddress,
      loc?.locationUri,
      loc?.displayName,
    ];

    candidates.forEach((candidate) => {
      const mailbox = normalizeMailboxAddress(candidate);
      if (mailbox) mailboxes.add(mailbox);
    });
  });

  return Array.from(mailboxes);
}

/**
 * Maps event type into Scope value used in AmenitySelections.
 */
function resolveScopeFromEventType(eventType) {
  return String(eventType || "").trim() === "seriesMaster" ? "series" : "instance";
}

/**
 * Builds the event instance key used as the SharePoint unique key.
 */
function buildEventInstanceKey({ seriesMasterId, iCalUId, originalStartUtc, startUtc, scope }) {
  const base = String(seriesMasterId || iCalUId || "").trim();
  if (!base) return "";
  if (scope === "series") return `${base}|series`;
  const point = String(originalStartUtc || startUtc || "").trim();
  if (!point) return "";
  return `${base}|${point}`;
}

/**
 * Converts current Outlook item id to Graph-compatible id.
 */
function getGraphEventIdFromItem(item) {
  const itemId = extractInlineItemId(item);
  if (!itemId) return "";
  const mailbox = Office?.context?.mailbox;
  if (!mailbox || typeof mailbox.convertToRestId !== "function") return itemId;

  try {
    return mailbox.convertToRestId(itemId, Office.MailboxEnums.RestVersion.v2_0) || itemId;
  } catch (error) {
    return itemId;
  }
}

/**
 * Reads Office async field values with a Promise wrapper.
 */
function readAsyncOfficeField(field) {
  return new Promise((resolve) => {
    if (!field || typeof field.getAsync !== "function") return resolve(null);
    field.getAsync((res) => {
      if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve(null);
      resolve(res.value);
    });
  });
}

/**
 * Returns amenity payload for logging (prefer explicit payload, then pending state, then UI snapshot).
 */
function resolveAmenitiesForDebug(explicitPayload) {
  if (hasAmenitiesPayload(explicitPayload)) return explicitPayload;
  if (hasAmenitiesPayload(pendingPayload)) return pendingPayload;
  const uiPayload = collectAmenitiesPayload();
  return hasAmenitiesPayload(uiPayload) ? uiPayload : {};
}

/**
 * Reads room mailbox context for current event from enhanced location.
 */
async function getRoomMailboxContext(item) {
  if (!item) return;

  const [locationText, enhanced, required] = await Promise.all([
    readAsyncOfficeField(item.location),
    readAsyncOfficeField(item.enhancedLocation),
    readAsyncOfficeField(item.requiredAttendees),
  ]);

  const detailedEnhanced = (Array.isArray(enhanced) ? enhanced : []).map((x) => ({
    displayName: x?.displayName || "",
    emailAddress: x?.emailAddress || "",
    id: x?.locationIdentifier?.id || "",
    type: x?.locationIdentifier?.type || "",
    raw: x, // เก็บ object เต็มไว้ดูละเอียด
  }));

  const enhancedWithMailbox = detailedEnhanced.map((x) => ({
    ...x,
    mailbox: normalizeMailboxAddress(x.emailAddress) || normalizeMailboxAddress(x.id),
  }));

  const roomLocations = enhancedWithMailbox.filter((x) => {
    if (!x.mailbox) return false;
    const locationType = normalizeText(x.type);
    return !locationType || locationType.includes("room");
  });

  const roomMailboxSet = new Set(roomLocations.map((x) => x.mailbox));
  const roomMailboxes = Array.from(roomMailboxSet);
  const requiredRoomAttendees = (Array.isArray(required) ? required : []).filter((attendee) =>
    roomMailboxSet.has(normalizeMailboxAddress(attendee?.emailAddress))
  );

  return {
    locationText: locationText || "",
    roomMailboxes,
    roomLocations,
    requiredRoomAttendees,
  };
}

