/**
 * Normalizes date values into minute-level ISO format for comparisons.
 */
function normalizeDateValue(value) {
  if (!value) return "";
  if (value instanceof Date) {
    return Number.isNaN(value.getTime()) ? "" : value.toISOString().slice(0, 16);
  }

  const parsedDate = new Date(value);
  if (!Number.isNaN(parsedDate.getTime())) return parsedDate.toISOString().slice(0, 16);
  return normalizeText(value);
}

/**
 * Reads a field value from Office item fields, supporting both direct and async fields.
 */
function getFieldValueAsync(field) {
  return new Promise((resolve) => {
    if (field == null) return resolve("");

    if (typeof field === "string" || typeof field === "number" || typeof field === "boolean" || field instanceof Date) {
      return resolve(field);
    }

    if (typeof field.displayName === "string" && field.displayName.trim()) {
      return resolve(field.displayName);
    }

    if (typeof field.getAsync === "function") {
      field.getAsync((res) => {
        if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve("");
        resolve(res.value);
      });
      return;
    }

    return resolve("");
  });
}

/**
 * Builds a comparable fingerprint for the current event (id, subject, times, location).
 */
async function buildItemFingerprint(item) {
  const subject = await getFieldValueAsync(item ? item.subject : "");
  const start = await getFieldValueAsync(item ? item.start : "");
  const end = await getFieldValueAsync(item ? item.end : "");
  const location = await getFieldValueAsync(item ? item.location : "");
  const savedItemId = await getSavedItemIdAsync(item);

  return {
    itemId: savedItemId,
    subject: normalizeText(subject),
    start: normalizeDateValue(start),
    end: normalizeDateValue(end),
    location: normalizeText(location),
  };
}

/**
 * Checks whether a saved draft fingerprint matches the current event fingerprint.
 */
function doesDraftFingerprintMatch(draftFingerprint, currentFingerprint) {
  if (!draftFingerprint || !currentFingerprint) return false;

  if (draftFingerprint.itemId && currentFingerprint.itemId) {
    return draftFingerprint.itemId === currentFingerprint.itemId;
  }

  const fields = ["subject", "start", "end", "location"];
  let comparableCount = 0;
  let matchCount = 0;

  fields.forEach((field) => {
    const draftValue = draftFingerprint[field];
    const currentValue = currentFingerprint[field];
    if (!draftValue || !currentValue) return;

    comparableCount += 1;
    if (draftValue === currentValue) matchCount += 1;
  });

  const hasStartEndMatch =
    Boolean(draftFingerprint.start && currentFingerprint.start && draftFingerprint.end && currentFingerprint.end) &&
    draftFingerprint.start === currentFingerprint.start &&
    draftFingerprint.end === currentFingerprint.end;

  if (hasStartEndMatch) return true;
  if (comparableCount === 0) return false;
  if (comparableCount <= 2) return matchCount === comparableCount;
  return matchCount >= 2;
}

/**
 * Builds a lightweight fingerprint quickly for fast draft writes.
 */
function buildQuickFingerprint(item) {
  const subjectValue = item && typeof item.subject === "string" ? item.subject : "";
  const locationValue =
    item && item.location && typeof item.location.displayName === "string" ? item.location.displayName : "";

  return {
    itemId: hasSavedItemId(item) ? String(item.itemId).trim() : "",
    subject: normalizeText(subjectValue),
    start: "",
    end: "",
    location: normalizeText(locationValue),
  };
}

/**
 * Parses the local draft envelope structure from localStorage.
 */
function parseLocalDraftEnvelope(raw) {
  if (!raw || typeof raw !== "string") return null;

  try {
    const parsed = JSON.parse(raw);
    if (!parsed || typeof parsed !== "object") return null;
    if (!hasAmenitiesPayload(parsed.payload)) return null;

    const fingerprint = parsed.fingerprint && typeof parsed.fingerprint === "object" ? parsed.fingerprint : {};
    return {
      updatedAt: Number(parsed.updatedAt) || 0,
      payload: parsed.payload,
      fingerprint,
    };
  } catch (error) {
    console.warn("localStorage draft envelope is not valid JSON:", error);
    return null;
  }
}

/**
 * Determines whether a recent draft can be used as a fallback restore.
 */
function shouldUseRecentDraftFallback(envelope, currentFingerprint) {
  if (!envelope || !hasAmenitiesPayload(envelope.payload)) return false;

  const updatedAt = Number(envelope.updatedAt) || 0;
  if (!updatedAt) return false;

  const age = Date.now() - updatedAt;
  if (age < 0 || age > DRAFT_RECENT_FALLBACK_MS) return false;

  const draftFingerprint = envelope.fingerprint || {};
  if (draftFingerprint.itemId && currentFingerprint.itemId && draftFingerprint.itemId !== currentFingerprint.itemId) {
    return false;
  }

  // For saved items, require identifiable match and avoid broad fallback
  // to prevent stale draft carry-over between different events.
  if (!draftFingerprint.itemId && currentFingerprint.itemId) {
    return false;
  }

  const hasComparableFingerprint = Boolean(
    (draftFingerprint.subject && currentFingerprint.subject) ||
      (draftFingerprint.start && currentFingerprint.start) ||
      (draftFingerprint.end && currentFingerprint.end) ||
      (draftFingerprint.location && currentFingerprint.location)
  );

  if (!hasComparableFingerprint) return true;
  return doesDraftFingerprintMatch(draftFingerprint, currentFingerprint);
}

/**
 * Keeps roaming draft records valid, sorted by recency, and within max size.
 */
function sortAndTrimDraftRecords(records) {
  const list = Array.isArray(records) ? records : [];
  return list
    .filter((record) => hasAmenitiesPayload(record && record.payload))
    .sort((a, b) => (Number(b.updatedAt) || 0) - (Number(a.updatedAt) || 0))
    .slice(0, MAX_ROAMING_DRAFTS);
}

/**
 * Parses draft records stored in roaming settings.
 */
function parseRoamingDraftRecords(raw) {
  if (!raw) return [];
  if (Array.isArray(raw)) return sortAndTrimDraftRecords(raw);
  if (typeof raw !== "string") return [];

  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? sortAndTrimDraftRecords(parsed) : [];
  } catch (error) {
    console.warn("roamingSettings draft is not valid JSON:", error);
    return [];
  }
}

/**
 * Writes normalized draft records back to roaming settings.
 */
function commitRoamingDraftRecords(records) {
  const roamingSettings = getRoamingSettings();
  if (!roamingSettings) return false;

  const normalizedRecords = sortAndTrimDraftRecords(records);
  try {
    roamingSettings.set(ROAMING_DRAFTS_KEY, JSON.stringify(normalizedRecords));
    roamingSettings.saveAsync(() => {});
    return true;
  } catch (error) {
    console.warn("Unable to save roamingSettings draft:", error);
    return false;
  }
}

/**
 * Loads draft records from roaming settings storage.
 */
function loadRoamingDraftRecords() {
  const roamingSettings = getRoamingSettings();
  if (!roamingSettings) return [];

  try {
    const raw = roamingSettings.get(ROAMING_DRAFTS_KEY);
    return parseRoamingDraftRecords(raw);
  } catch (error) {
    console.warn("Unable to read roamingSettings draft:", error);
    return [];
  }
}

/**
 * Saves a draft snapshot to roaming settings and enriches its fingerprint.
 */
function saveDraftToRoamingSettings(item, payload) {
  const roamingSettings = getRoamingSettings();
  if (!roamingSettings) return false;

  const recordId = `${Date.now()}_${Math.random().toString(36).slice(2, 10)}`;
  const updatedAt = Date.now();
  const quickRecord = {
    id: recordId,
    updatedAt,
    fingerprint: buildQuickFingerprint(item),
    payload: payload || {},
  };

  const records = loadRoamingDraftRecords();
  records.unshift(quickRecord);
  const committed = commitRoamingDraftRecords(records);

  buildItemFingerprint(item)
    .then((fullFingerprint) => {
      const latestRecords = loadRoamingDraftRecords();
      const idx = latestRecords.findIndex((record) => record && record.id === recordId);
      if (idx < 0) return;
      latestRecords[idx] = {
        ...latestRecords[idx],
        fingerprint: fullFingerprint,
      };
      commitRoamingDraftRecords(latestRecords);
    })
    .catch((error) => {
      console.warn("Unable to enrich roamingSettings draft fingerprint:", error);
    });

  return committed;
}

/**
 * Reads and matches a draft payload from roaming settings.
 */
async function readDraftFromRoamingSettings(item) {
  const records = loadRoamingDraftRecords();
  if (records.length === 0) return {};

  const currentFingerprint = await buildItemFingerprint(item);

  const matched = records.find((record) => doesDraftFingerprintMatch(record.fingerprint || {}, currentFingerprint));
  if (matched && hasAmenitiesPayload(matched.payload)) return matched.payload;

  const fallback = records.find((record) => shouldUseRecentDraftFallback(record, currentFingerprint));
  if (fallback && hasAmenitiesPayload(fallback.payload)) return fallback.payload;

  return {};
}

/**
 * Clears draft records from roaming settings.
 */
function clearDraftFromRoamingSettings() {
  const roamingSettings = getRoamingSettings();
  if (!roamingSettings) return false;

  try {
    if (typeof roamingSettings.remove === "function") {
      roamingSettings.remove(ROAMING_DRAFTS_KEY);
    } else {
      roamingSettings.set(ROAMING_DRAFTS_KEY, JSON.stringify([]));
    }
    roamingSettings.saveAsync(() => {});
    return true;
  } catch (error) {
    console.warn("Unable to clear roamingSettings draft:", error);
    return false;
  }
}

/**
 * Builds the localStorage key scoped to the current mailbox user.
 */
function getLocalDraftStorageKey() {
  const mailbox = Office?.context?.mailbox;
  const email = mailbox?.userProfile?.emailAddress || "default";
  return `${LOCAL_DRAFT_STORAGE_PREFIX}:${String(email).toLowerCase()}`;
}

/**
 * Returns localStorage when accessible in the current host context.
 */
function getSafeLocalStorage() {
  try {
    return globalThis.localStorage || null;
  } catch (error) {
    return null;
  }
}

/**
 * Reads and matches a draft payload from localStorage.
 */
async function readDraftFromLocalStorage(item) {
  const storage = getSafeLocalStorage();
  if (!storage) return {};

  try {
    const raw = storage.getItem(getLocalDraftStorageKey());
    const envelope = parseLocalDraftEnvelope(raw);
    if (!envelope) return {};

    const currentFingerprint = await buildItemFingerprint(item);
    if (doesDraftFingerprintMatch(envelope.fingerprint, currentFingerprint)) return envelope.payload;
    if (shouldUseRecentDraftFallback(envelope, currentFingerprint)) return envelope.payload;

    return {};
  } catch (error) {
    console.warn("Unable to read draft from localStorage:", error);
    return {};
  }
}

/**
 * Updates an existing local draft with a richer fingerprint after initial save.
 */
async function enrichLocalDraftFingerprint(item, expectedUpdatedAt) {
  const storage = getSafeLocalStorage();
  if (!storage) return;

  try {
    const fullFingerprint = await buildItemFingerprint(item);
    const key = getLocalDraftStorageKey();
    const raw = storage.getItem(key);
    const envelope = parseLocalDraftEnvelope(raw);
    if (!envelope || !hasAmenitiesPayload(envelope.payload)) return;
    if ((Number(envelope.updatedAt) || 0) !== expectedUpdatedAt) return;

    storage.setItem(
      key,
      JSON.stringify({
        updatedAt: envelope.updatedAt,
        payload: envelope.payload,
        fingerprint: fullFingerprint,
      })
    );
  } catch (error) {
    console.warn("Unable to enrich localStorage draft fingerprint:", error);
  }
}

/**
 * Writes draft payload to localStorage with a quick fingerprint.
 */
function writeDraftToLocalStorage(item, payload) {
  const storage = getSafeLocalStorage();
  if (!storage) return false;

  try {
    const updatedAt = Date.now();
    const envelope = {
      updatedAt,
      fingerprint: buildQuickFingerprint(item),
      payload: payload || {},
    };
    storage.setItem(getLocalDraftStorageKey(), JSON.stringify(envelope));
    enrichLocalDraftFingerprint(item, updatedAt).catch((error) => {
      console.warn("Unable to enrich localStorage draft:", error);
    });
    return true;
  } catch (error) {
    console.warn("Unable to save draft to localStorage:", error);
    return false;
  }
}

/**
 * Removes local draft payload from localStorage.
 */
function clearDraftFromLocalStorage() {
  const storage = getSafeLocalStorage();
  if (!storage) return false;

  try {
    storage.removeItem(getLocalDraftStorageKey());
    return true;
  } catch (error) {
    console.warn("Unable to clear localStorage draft:", error);
    return false;
  }
}

/**
 * Checks whether item.sessionData APIs are available for this host.
 */
function hasSessionDataApi(item) {
  return Boolean(
    item &&
      item.sessionData &&
      typeof item.sessionData.getAsync === "function" &&
      typeof item.sessionData.setAsync === "function"
  );
}

/**
 * Reads a draft payload from item sessionData.
 */
function readDraftFromSessionData(item) {
  return new Promise((resolve) => {
    if (!hasSessionDataApi(item)) return resolve({});
    item.sessionData.getAsync(DRAFT_ROOM_SERVICES_KEY, (res) => {
      if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve({});
      const raw = typeof res.value === "string" ? res.value : "";
      resolve(parseAmenitiesPayload(raw, "sessionData draft"));
    });
  });
}

/**
 * Writes draft payload to item sessionData.
 */
function writeDraftToSessionData(item, payload) {
  return new Promise((resolve) => {
    if (!hasSessionDataApi(item)) return resolve(false);
    item.sessionData.setAsync(DRAFT_ROOM_SERVICES_KEY, JSON.stringify(payload || {}), (res) => {
      resolve(res.status === Office.AsyncResultStatus.Succeeded);
    });
  });
}

/**
 * Removes draft payload from item sessionData.
 */
function clearDraftFromSessionData(item) {
  return new Promise((resolve) => {
    if (!hasSessionDataApi(item) || typeof item.sessionData.removeAsync !== "function") return resolve(false);
    item.sessionData.removeAsync(DRAFT_ROOM_SERVICES_KEY, (res) => {
      resolve(res.status === Office.AsyncResultStatus.Succeeded);
    });
  });
}

/**
 * Escapes text for safe HTML rendering in dynamic markup.
 */
function escapeHtml(input) {
  return String(input).replace(/[&<>"']/g, (ch) => {
    const map = {
      "&": "&amp;",
      "<": "&lt;",
      ">": "&gt;",
      '"': "&quot;",
      "'": "&#39;",
    };
    return map[ch];
  });
}

/**
 * Finds the best display label for an amenity from SharePoint fields.
 */
function resolveAmenityLabel(fields) {
  if (!fields || typeof fields !== "object") return "";
  const valuesToTry = [
    fields.Title,
    fields.Amenity,
    fields.Amenities,
    fields.AmenityName,
    fields.Name,
    fields.DisplayName,
  ];

  for (const value of valuesToTry) {
    if (typeof value === "string" && value.trim()) return value.trim();
  }

  const dynamicMatch = Object.entries(fields).find(([key, value]) => {
    if (key.startsWith("@")) return false;
    if (typeof value !== "string" || !value.trim()) return false;

    const lowerKey = key.toLowerCase();
    return lowerKey.includes("amenit") || lowerKey.endsWith("name") || lowerKey === "name";
  });

  return dynamicMatch ? dynamicMatch[1].trim() : "";
}

/**
 * Resolves amenity group text from SharePoint fields.
 */
function resolveAmenityGroup(fields) {
  if (!fields || typeof fields !== "object") return "Other";

  const valuesToTry = [
    fields.Group,
    fields.AmenityGroup,
    fields.AmenitiesGroup,
    fields.GroupName,
    fields.Category,
  ];

  for (const value of valuesToTry) {
    if (typeof value === "string" && value.trim()) return value.trim();
  }

  const dynamicMatch = Object.entries(fields).find(([key, value]) => {
    if (key.startsWith("@")) return false;
    if (typeof value !== "string" || !value.trim()) return false;

    const lowerKey = key.toLowerCase();
    return lowerKey.includes("group") || lowerKey.includes("category");
  });

  return dynamicMatch ? dynamicMatch[1].trim() : "Other";
}

/**
 * Resolves amenity code from SharePoint fields.
 */
function resolveAmenityCode(fields, fallbackLabel) {
  if (!fields || typeof fields !== "object") return String(fallbackLabel || "").trim();

  const valuesToTry = [
    fields.Code,
    fields.AmenityCode,
    fields.AmenitiesCode,
  ];

  for (const value of valuesToTry) {
    if (typeof value === "string" && value.trim()) return value.trim();
  }

  const dynamicMatch = Object.entries(fields).find(([key, value]) => {
    if (key.startsWith("@")) return false;
    if (typeof value !== "string" || !value.trim()) return false;
    return key.toLowerCase().includes("code");
  });

  if (dynamicMatch) return dynamicMatch[1].trim();
  return String(fallbackLabel || "").trim();
}

/**
 * Renders amenity rows (checkbox and quantity) into the task pane.
 */
function renderAmenities(items) {
  const container = document.getElementById("amenitiesContainer");
  // console.log("=======================================================")
  // console.log(items)
  if (!container) return;

  container.innerHTML = "";
  const skippedItems = [];
  const groupedItems = new Map();

  items.forEach((item, index) => {
    const label = resolveAmenityLabel(item.fields);
    if (!label) {
      skippedItems.push(item);
      return;
    }

    const groupName = resolveAmenityGroup(item.fields) || "Other";
    const code = resolveAmenityCode(item.fields, label);
    if (!groupedItems.has(groupName)) groupedItems.set(groupName, []);
    groupedItems.get(groupName).push({
      rawId: item.id ?? index,
      label,
      group: groupName,
      code,
    });
  });

  const sortedGroups = Array.from(groupedItems.entries()).sort((a, b) =>
    a[0].localeCompare(b[0], undefined, { sensitivity: "base" })
  );

  sortedGroups.forEach(([groupName, amenityRows]) => {
    const safeGroupName = escapeHtml(groupName);
    container.insertAdjacentHTML(
      "beforeend",
      `<div class="amenity-group-title">${safeGroupName}</div>`
    );

    amenityRows
      .sort((a, b) => a.label.localeCompare(b.label, undefined, { sensitivity: "base" }))
      .forEach(({ rawId, label, group, code }) => {
        const amenityId = String(rawId);
        const safeId = escapeHtml(amenityId);
        const safeLabel = escapeHtml(label);
        const safeGroup = escapeHtml(group);
        const safeCode = escapeHtml(code);

        container.insertAdjacentHTML(
          "beforeend",
          `
          <div class="fluent-row">
            <label class="fluent-checkbox">
              <input type="checkbox" class="amenity-check checkbox-size" data-id="${safeId}" data-label="${safeLabel}" data-group="${safeGroup}" data-code="${safeCode}">
              <span>${safeLabel}</span>
            </label>
            <input type="number" class="amenity-qty" data-id="${safeId}" min="0" placeholder="0">
          </div>
        `
        );
      });
  });

  if (skippedItems.length > 0) {
    console.warn("Some SharePoint items were skipped because no label field was found:", skippedItems);
  }
}

/**
 * Collects selected amenities from the UI into a persistable payload.
 */
function collectAmenitiesPayload() {
  const checks = document.querySelectorAll(".amenity-check");
  const qtyInputs = document.querySelectorAll(".amenity-qty");
  const qtyById = new Map();
  qtyInputs.forEach((input) => {
    qtyById.set(input.dataset.id, input);
  });

  const payload = {};
  checks.forEach((check) => {
    const amenityId = check.dataset.id || "";
    const label = (check.dataset.label || "").trim() || `amenity_${amenityId || "unknown"}`;
    const group = (check.dataset.group || "").trim() || "Other";
    const code = (check.dataset.code || "").trim() || label;
    const qtyInput = qtyById.get(amenityId);
    const qty = qtyInput ? +qtyInput.value || 0 : 0;
    const isSelected = Boolean(check.checked);
    if (!isSelected && qty <= 0) return;

    payload[label] = {
      id: amenityId,
      code,
      group,
      selected: isSelected,
      qty,
    };
  });

  return payload;
}

/**
 * Loads Outlook custom properties for the current item.
 */
function loadCustomProps(item) {
  return new Promise((resolve) => {
    item.loadCustomPropertiesAsync((res) => {
      if (res.status === Office.AsyncResultStatus.Succeeded) resolve(res.value);
      else resolve(null);
    });
  });
}

/**
 * Reads persisted amenities from custom properties.
 */
async function readSavedAmenities(item) {
  const props = await loadCustomProps(item);
  if (!props) return {};

  const raw = props.get(ROOM_SERVICES_KEY);
  return parseAmenitiesPayload(raw, ROOM_SERVICES_KEY);
}

/**
 * Reads event metadata from Microsoft Graph for the current compose item.
 */
async function fetchGraphEventDetails(token, item) {
  const graphEventId = getGraphEventIdFromItem(item);
  if (!graphEventId) return null;

  const select = [
    "id",
    "subject",
    "start",
    "end",
    "locations",
    "iCalUId",
    "seriesMasterId",
    "type",
    "originalStart",
    "isCancelled",
    "organizer",
  ].join(",");
  const url = `${GRAPH_ME_EVENTS_URL}/${encodeURIComponent(graphEventId)}?$select=${encodeURIComponent(select)}`;
  const response = await fetch(url, {
    method: "GET",
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    const errText = await response.text().catch(() => "");
    console.warn("Unable to read event details from Graph:", response.status, errText);
    return null;
  }

  return response.json();
}

/**
 * Builds SharePoint fields payload for AmenitySelections list.
 */
async function buildAmenitySelectionsFields(item, token, payload) {
  if (!item) return null;
  const graphEvent = await fetchGraphEventDetails(token, item);
  const roomContext = await getRoomMailboxContext(item);
  const graphRoomMailboxes = extractRoomMailboxesFromGraphEvent(graphEvent);
  const roomMailboxes = Array.from(
    new Set([
      ...(roomContext?.roomMailboxes || []),
      ...graphRoomMailboxes,
    ])
  );
  if (roomMailboxes.length === 0) {
    console.debug("[SYNC][AmenitySelections] skipped: no room mailbox found");
    return null;
  }

  const fallbackEventId = getGraphEventIdFromItem(item) || extractInlineItemId(item);
  const subjectValue = await getFieldValueAsync(item.subject);
  const startValue = await getFieldValueAsync(item.start);
  const endValue = await getFieldValueAsync(item.end);

  const startUtc = toUtcIsoString(startValue) || parseGraphDateTimeZoneToUtc(graphEvent?.start);
  const endUtc = toUtcIsoString(endValue) || parseGraphDateTimeZoneToUtc(graphEvent?.end);
  const iCalUId = String(graphEvent?.iCalUId || fallbackEventId || "").trim();
  const seriesMasterId = String(graphEvent?.seriesMasterId || "").trim();
  const eventType = String(graphEvent?.type || "singleInstance").trim() || "singleInstance";
  const scope = resolveScopeFromEventType(eventType);
  const originalStartUtc = toUtcIsoString(graphEvent?.originalStart) || startUtc;
  const eventInstanceKey = buildEventInstanceKey({
    seriesMasterId,
    iCalUId,
    originalStartUtc,
    startUtc,
    scope,
  });

  if (!eventInstanceKey) return null;

  const profile = Office?.context?.mailbox?.userProfile;
  const organizerEmail =
    normalizeMailboxAddress(graphEvent?.organizer?.emailAddress?.address) ||
    normalizeMailboxAddress(profile?.emailAddress);
  const organizerName = String(graphEvent?.organizer?.emailAddress?.name || profile?.displayName || "").trim();
  const selectedCodes = getSelectedAmenityCodes(payload);
  const titleText = String(graphEvent?.subject || subjectValue || "").trim() || "(no subject)";

  const fields = {
    Title: titleText,
    EventInstanceKey: eventInstanceKey,
    ICalUId: iCalUId,
    SeriesMasterId: seriesMasterId,
    EventType: eventType,
    Scope: scope,
    OriginalStartUtc: originalStartUtc,
    StartUtc: startUtc,
    EndUtc: endUtc,
    OrganizerEmail: organizerEmail,
    OrganizerName: organizerName,
    RoomMailboxesJson: JSON.stringify(roomMailboxes),
    SelectedCodesJson: JSON.stringify(selectedCodes),
    IsCancelled: Boolean(graphEvent?.isCancelled),
    LastUpdatedUtc: new Date().toISOString(),
  };

  return {
    eventInstanceKey,
    fields,
    signature: JSON.stringify(fields),
  };
}

/**
 * Finds existing AmenitySelections row by EventInstanceKey.
 */
async function findAmenitySelectionItemIdByKey(token, eventInstanceKey) {
  const filter = encodeURIComponent(`fields/EventInstanceKey eq '${escapeODataString(eventInstanceKey)}'`);
  const queryUrl = `${AMENITY_SELECTIONS_LIST_ITEMS_URL}?$top=1&$select=id&$expand=fields($select=EventInstanceKey)&$filter=${filter}`;
  const response = await fetch(queryUrl, {
    method: "GET",
    headers: {
      Authorization: `Bearer ${token}`,
    },
  });

  if (!response.ok) {
    const errText = await response.text().catch(() => "");
    throw new Error(`Lookup AmenitySelections failed (${response.status}): ${errText}`);
  }

  const data = await response.json();
  return data?.value?.[0]?.id ? String(data.value[0].id) : "";
}

/**
 * Creates or updates AmenitySelections item by EventInstanceKey.
 */
async function upsertAmenitySelectionsItem(token, eventInstanceKey, fields) {
  const existingItemId = await findAmenitySelectionItemIdByKey(token, eventInstanceKey);

  if (existingItemId) {
    const updateUrl = `${AMENITY_SELECTIONS_LIST_ITEMS_URL}/${encodeURIComponent(existingItemId)}/fields`;
    const updateResponse = await fetch(updateUrl, {
      method: "PATCH",
      headers: {
        Authorization: `Bearer ${token}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify(fields),
    });

    if (!updateResponse.ok) {
      const errText = await updateResponse.text().catch(() => "");
      throw new Error(`Update AmenitySelections failed (${updateResponse.status}): ${errText}`);
    }
    return "updated";
  }

  const createResponse = await fetch(AMENITY_SELECTIONS_LIST_ITEMS_URL, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({ fields }),
  });

  if (!createResponse.ok) {
    const errText = await createResponse.text().catch(() => "");
    throw new Error(`Create AmenitySelections failed (${createResponse.status}): ${errText}`);
  }
  return "created";
}

/**
 * Syncs current payload to AmenitySelections when event key is available.
 */
async function syncAmenitySelectionsIfPossible(explicitPayload, options = {}) {
  const item = Office?.context?.mailbox?.item;
  if (!item) {
    console.debug("[SYNC][AmenitySelections] skipped: no mailbox item");
    return false;
  }
  if (!(await hasSavedItemIdAsync(item))) {
    console.debug("[SYNC][AmenitySelections] skipped: event is not saved yet");
    return false;
  }

  const token = await getAccessToken();
  if (!token) {
    console.warn("[SYNC][AmenitySelections] skipped: no Graph token");
    return false;
  }

  const payload = cloneAmenitiesPayload(resolveAmenitiesForPersistence(explicitPayload));
  const record = await buildAmenitySelectionsFields(item, token, payload);
  if (!record || !record.eventInstanceKey) {
    console.debug("[SYNC][AmenitySelections] skipped: key or room context not available");
    return false;
  }

  const force = Boolean(options.force);
  const reason = options.reason || "auto";
  if (!force && lastAmenitySelectionsSignature && lastAmenitySelectionsSignature === record.signature) {
    console.debug("[SYNC][AmenitySelections] skipped: no data change", { reason, key: record.eventInstanceKey });
    return true;
  }

  const result = await upsertAmenitySelectionsItem(token, record.eventInstanceKey, record.fields);
  lastAmenitySelectionsSignature = record.signature;
  console.log("[SYNC][AmenitySelections]", { reason, action: result, key: record.eventInstanceKey });
  return true;
}

/**
 * Clears the pending AmenitySelections upsert timer.
 */
function clearAmenitySelectionsUpsertTimer() {
  if (!amenitySelectionsUpsertTimer) return;
  clearTimeout(amenitySelectionsUpsertTimer);
  amenitySelectionsUpsertTimer = null;
}

/**
 * Schedules a debounced AmenitySelections upsert.
 */
function scheduleAmenitySelectionsUpsert(reason, explicitPayload) {
  pendingAmenitySelectionsUpsertPayload = cloneAmenitiesPayload(resolveAmenitiesForPersistence(explicitPayload));
  clearAmenitySelectionsUpsertTimer();
  amenitySelectionsUpsertTimer = setTimeout(() => {
    const snapshot = cloneAmenitiesPayload(pendingAmenitySelectionsUpsertPayload);
    pendingAmenitySelectionsUpsertPayload = null;
    syncAmenitySelectionsIfPossible(snapshot, { reason, force: false }).catch((error) => {
      console.error("AmenitySelections debounced sync failed:", error);
    });
  }, AMENITY_SELECTIONS_UPSERT_DELAY_MS);
}

/**
 * Runs an immediate checkpoint sync (used after successful save checkpoints).
 */
async function runAmenitySelectionsCheckpoint(reason, explicitPayload) {
  clearAmenitySelectionsUpsertTimer();
  pendingAmenitySelectionsUpsertPayload = null;
  await syncAmenitySelectionsIfPossible(explicitPayload, { reason, force: true });
}

/**
 * Detects save checkpoints by watching when the compose item receives a saved id.
 */
async function probeSaveCheckpoint() {
  const item = Office?.context?.mailbox?.item;
  if (!item) return;

  const savedId = await getSavedItemIdAsync(item);
  if (!savedId) {
    lastObservedSavedItemId = "";
    return;
  }

  if (savedId === lastObservedSavedItemId) return;
  lastObservedSavedItemId = savedId;
  await runAmenitySelectionsCheckpoint("save-checkpoint");
}

/**
 * Reads draft amenities from supported draft stores in priority order.
 */
async function readDraftAmenities(item) {
  const fromSessionData = await readDraftFromSessionData(item);
  if (hasAmenitiesPayload(fromSessionData)) return fromSessionData;

  const itemIsSaved = await hasSavedItemIdAsync(item);
  if (!itemIsSaved) {
    return {};
  }

  const fromRoamingSettings = await readDraftFromRoamingSettings(item);
  if (hasAmenitiesPayload(fromRoamingSettings)) return fromRoamingSettings;

  return readDraftFromLocalStorage(item);
}

/**
 * Writes draft amenities to available draft stores.
 */
async function saveDraftAmenities(item, payload) {
  const sessionWritePromise = hasSessionDataApi(item) ? writeDraftToSessionData(item, payload) : Promise.resolve(false);
  const roamingSaved = saveDraftToRoamingSettings(item, payload);
  const localWritePromise = writeDraftToLocalStorage(item, payload);
  const [sessionSaved, localSaved] = await Promise.all([sessionWritePromise, localWritePromise]);
  return sessionSaved || localSaved || roamingSaved;
}

/**
 * Clears draft amenities from all draft stores.
 */
async function clearDraftAmenities(item) {
  const clearLocalPromise = Promise.resolve(clearDraftFromLocalStorage());
  const clearRoamingPromise = Promise.resolve(clearDraftFromRoamingSettings());
  if (hasSessionDataApi(item)) {
    await Promise.all([clearDraftFromSessionData(item), clearLocalPromise, clearRoamingPromise]);
    return;
  }
  await Promise.all([clearLocalPromise, clearRoamingPromise]);
}

/**
 * Applies a payload back to checkbox and quantity controls.
 */
function applyAmenitiesPayload(savedPayload) {
  if (!hasAmenitiesPayload(savedPayload)) return;

  const savedById = new Map();
  Object.values(savedPayload).forEach((entry) => {
    if (!entry || typeof entry !== "object") return;
    const entryId = entry.id == null ? "" : String(entry.id);
    if (entryId) savedById.set(entryId, entry);
  });

  const checks = document.querySelectorAll(".amenity-check");
  const qtyInputs = document.querySelectorAll(".amenity-qty");
  const qtyById = new Map();
  qtyInputs.forEach((input) => {
    qtyById.set(input.dataset.id || "", input);
  });

  checks.forEach((check) => {
    const amenityId = check.dataset.id || "";
    const label = (check.dataset.label || "").trim();
    const fromId = amenityId ? savedById.get(amenityId) : null;
    const fromLabel = label ? savedPayload[label] : null;
    const saved = fromId || fromLabel;
    if (!saved || typeof saved !== "object") return;

    check.checked = Boolean(saved.selected);
    const qtyInput = qtyById.get(amenityId);
    if (qtyInput) {
      const qtyValue = Number(saved.qty);
      qtyInput.value = Number.isFinite(qtyValue) ? String(Math.max(0, qtyValue)) : "0";
    }
  });
}

/**
 * Restores saved or draft amenities when the pane opens.
 */
async function restoreSavedSelections(item) {
  // Prioritize draft first so recently changed selections appear immediately
  // even if custom-properties persistence is still in flight.
  const draftPayload = await readDraftAmenities(item);
  if (hasAmenitiesPayload(draftPayload)) {
    applyAmenitiesPayload(draftPayload);
    pendingPayload = draftPayload;
    const itemIsSaved = await hasSavedItemIdAsync(item);
    if (itemIsSaved) {
      flushPendingSelections("restore-draft").catch((error) => {
        console.error("Draft migration failed:", error);
      });
      return;
    }
    setStatus("Selections are pending. Save the event to keep amenities.");
    schedulePendingFlush();
    return;
  }

  const savedPayload = await readSavedAmenities(item);
  if (hasAmenitiesPayload(savedPayload)) {
    applyAmenitiesPayload(savedPayload);
    pendingPayload = null;
    await clearDraftAmenities(item);
    scheduleAmenitySelectionsUpsert("restore-saved", savedPayload);
    setStatus("");
    return;
  }
  pendingPayload = null;
  setStatus("");
}

/**
 * Updates the status message shown in the task pane.
 */
function setStatus(text) {
  const statusEl = document.getElementById("status");
  if (statusEl) statusEl.textContent = text || "";
}

/**
 * Persists amenities to custom properties when the event is already saved.
 */
async function persistSelections(payload) {
  const item = Office.context.mailbox.item;
  if (!(await hasSavedItemIdAsync(item))) return false;
  const safePayload = cloneAmenitiesPayload(payload);
  return saveCustomProps(item, ROOM_SERVICES_KEY, JSON.stringify(safePayload));
}

/**
 * Clears the pending flush timer if one is active.
 */
function clearPendingFlushTimer() {
  if (!pendingFlushTimer) return;
  clearTimeout(pendingFlushTimer);
  pendingFlushTimer = null;
}

/**
 * Schedules a delayed retry to flush pending amenities.
 */
function schedulePendingFlush() {
  clearPendingFlushTimer();
  pendingFlushTimer = setTimeout(() => {
    flushPendingSelections("pending-retry").catch((error) => {
      console.error("Pending amenities flush failed:", error);
    });
  }, PENDING_FLUSH_DELAY_MS);
}

/**
 * Attempts to persist pending selections and handles retry behavior.
 */
async function flushPendingSelections(triggerReason = "auto") {
  if (!pendingPayload) return;
  const payloadSnapshot = cloneAmenitiesPayload(pendingPayload);

  const saved = await persistSelections(payloadSnapshot);
  if (saved) {
    if (triggerReason === "pending-retry" || triggerReason === "restore-draft") {
      await runAmenitySelectionsCheckpoint(triggerReason, payloadSnapshot);
    } else {
      scheduleAmenitySelectionsUpsert(triggerReason, payloadSnapshot);
    }
    await clearDraftAmenities(Office.context.mailbox.item);
    pendingPayload = null;
    clearPendingFlushTimer();
    setStatus("");
    return;
  }

  // setStatus("Selections are pending. Save the event to keep amenities.");
  schedulePendingFlush();
}

/**
 * Debounces selection changes before attempting a flush.
 */
function scheduleAutoSave() {
  if (autoSaveTimer) clearTimeout(autoSaveTimer);
  autoSaveTimer = setTimeout(() => {
    flushPendingSelections("autosave-change")
      .catch((error) => {
        console.error("Auto-save failed:", error);
      });
  }, AUTO_SAVE_DELAY_MS);
}

/**
 * Handles checkbox and quantity changes and updates draft state.
 */
function onAmenitiesValueChanged(event) {
  const target = event.target;
  if (!target || !target.classList) return;
  if (!target.classList.contains("amenity-check") && !target.classList.contains("amenity-qty")) return;
  const item = Office.context.mailbox.item;
  pendingPayload = collectAmenitiesPayload();
  if (hasAmenitiesPayload(pendingPayload)) {
    saveDraftAmenities(item, pendingPayload).catch((error) => {
      console.error("Draft save failed:", error);
    });
  } else {
    clearDraftAmenities(item).catch((error) => {
      console.error("Draft clear failed:", error);
    });
  }

  // Trigger an immediate flush attempt for faster persistence on saved items,
  // while keeping the existing debounce as a retry path.
  flushPendingSelections("immediate-change").catch((error) => {
    console.error("Immediate flush failed:", error);
  });

  void logRoomMailboxDetails("amenity-change", pendingPayload);
  scheduleAutoSave();
}

/**
 * Returns true when host supports Nested App Authentication requirement set.
 */
function isNestedAppAuthSupported() {
  try {
    return Boolean(
      Office?.context?.requirements?.isSetSupported &&
      Office.context.requirements.isSetSupported("NestedAppAuth", "1.1")
    );
  } catch (error) {
    return false;
  }
}

/**
 * Detects interaction-required style MSAL errors.
 */
function isInteractionRequiredError(error) {
  const code = String(error?.errorCode || "").toLowerCase();
  return (
    error instanceof msal.InteractionRequiredAuthError ||
    code === "interaction_required" ||
    code === "login_required" ||
    code === "consent_required" ||
    code === "no_tokens_found"
  );
}

/**
 * Initializes MSAL and sets active account when available.
 */
async function initializeMsal() {
  if (msalInstance) {
    const active = msalInstance.getActiveAccount();
    if (active) return msalInstance;
  }

  if (!msalInitPromise) {
    msalInitPromise = (async () => {
      const canUseNaaFactory = typeof msal?.createNestablePublicClientApplication === "function";
      const naaSupported = isNestedAppAuthSupported();

      if (canUseNaaFactory && naaSupported) {
        msalInstance = await msal.createNestablePublicClientApplication(msalConfig);
      } else {
        msalInstance = new msal.PublicClientApplication(msalConfig);
        if (typeof msalInstance.initialize === "function") {
          await msalInstance.initialize();
        }
      }

      const active = msalInstance.getActiveAccount();
      if (!active) {
        const accounts = msalInstance.getAllAccounts();
        if (accounts.length > 0) {
          msalInstance.setActiveAccount(accounts[0]);
        }
      }

      return msalInstance;
    })().catch((error) => {
      msalInitPromise = null;
      msalInstance = null;
      throw error;
    });
  }

  return msalInitPromise;
}

/**
 * Acquires a Microsoft Graph access token for loading amenities.
 */
async function getAccessToken() {
  await initializeMsal();
  if (!msalInstance) return null;

  let account = msalInstance.getActiveAccount();
  if (!account) {
    const accounts = msalInstance.getAllAccounts();
    account = accounts.length > 0 ? accounts[0] : null;
  }

  const loginHint = Office?.context?.mailbox?.userProfile?.emailAddress;

  try {
    const silentRequest = {
      ...loginRequest,
      loginHint,
    };
    if (account) {
      silentRequest.account = account;
    }

    const tokenResponse = await msalInstance.acquireTokenSilent(silentRequest);
    if (tokenResponse?.account) {
      msalInstance.setActiveAccount(tokenResponse.account);
    }
    return tokenResponse.accessToken;
  } catch (error) {
    if (isInteractionRequiredError(error)) {
      const interactiveRequest = {
        ...loginRequest,
        loginHint,
      };
      if (!account) {
        interactiveRequest.prompt = "select_account";
      }
      if (account) {
        interactiveRequest.account = account;
      }

      let tokenResponse = null;
      try {
        tokenResponse = await msalInstance.acquireTokenPopup(interactiveRequest);
      } catch (popupError) {
        const popupCode = String(popupError?.errorCode || "");
        if (popupCode === "popup_window_error") {
          console.warn(
            "Popup auth failed (popup_window_error). Check NAA config and SPA redirect URI (brk-multihub://<origin>).",
            popupError
          );
        }
        throw popupError;
      }
      if (tokenResponse && tokenResponse.account) {
        msalInstance.setActiveAccount(tokenResponse.account);
      }
      return tokenResponse.accessToken;
    }

    throw error;
  }
}

/**
 * Loads amenities from Graph, renders UI, and restores saved selections.
 */
async function loadAmenities() {
  const statusEl = document.getElementById("status");
  try {
    if (statusEl) statusEl.textContent = "Loading amenities...";
    const token = await getAccessToken();
    if (!token) return;

    const response = await fetch(AMENITIES_LIST_URL, {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    });

    if (!response.ok) {
      const errText = await response.text().catch(() => "");
      if (statusEl) statusEl.textContent = `Load failed (${response.status})`;
      console.error("Graph request failed:", response.status, errText);
      return;
    }

    const data = await response.json();
    const items = Array.isArray(data.value) ? data.value : [];
    renderAmenities(items);
    await restoreSavedSelections(Office.context.mailbox.item);
    runAmenitySelectionsCheckpoint("pane-load").catch((error) => {
      console.error("Initial AmenitySelections checkpoint failed:", error);
    });
    if (statusEl) statusEl.textContent = "";
  } catch (error) {
    console.error("Unable to load amenities:", error);
    const code = error && error.errorCode ? error.errorCode : "";
    if (statusEl) statusEl.textContent = code ? `Unable to load amenities. (${code})` : "Unable to load amenities.";
  }
}

