/**
 * Saves a key/value into Outlook custom properties for the current item.
 */
async function saveCustomProps(item, key, val) {
  if (!(await hasSavedItemIdAsync(item))) return false;

  return new Promise((resolve) => {
    item.loadCustomPropertiesAsync((res) => {
      if (res.status !== Office.AsyncResultStatus.Succeeded) return resolve(false);
      const props = res.value;
      props.set(key, val);
      props.saveAsync((saveResult) => resolve(saveResult.status === Office.AsyncResultStatus.Succeeded));
    });
  });
}



